const systemPrompt = `Eres un arquitecto experto en n8n que convierte instrucciones en lenguaje natural en workflows JSON compatibles con n8n.

Reglas:
1. Responde ÚNICAMENTE con JSON válido. Sin explicaciones, sin bloques de código.
2. Usa solo nodos oficiales de n8n-nodes-base.
3. NUNCA uses: executeCommand, readWriteFile, localFileTrigger.
4. NUNCA incluyas credenciales reales.
5. active: false siempre.
6. Estructura: { name, nodes, connections, active: false, settings: { executionOrder: "v1" } }
7. Primer nodo (trigger) en position [250, 300]. Cada siguiente: X += 250.
8. Si faltan credenciales, agrega un Sticky Note con warnings.`;

const body = $input.first().json.body || $input.first().json;
return [{ json: { systemPrompt, userPrompt: body.description, model: body.model || 'ollama' } }];

const item = $input.first().json;
let raw;

// Ollama format
if (item.message?.content) raw = item.message.content;
// Claude format
else if (item.content?.[0]?.text) raw = item.content[0].text;
// OpenAI format
else if (item.choices?.[0]?.message?.content) raw = item.choices[0].message.content;
else throw new Error('Formato de respuesta no reconocido: ' + JSON.stringify(Object.keys(item)));

// Limpiar markdown fences si el modelo los incluyó igual
raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

try {
  const workflow = JSON.parse(raw);
  // Forzar seguridad — nunca activar automáticamente
  workflow.active = false;
  return [{ json: { workflow, valid: true } }];
} catch (e) {
  return [{ json: { error: 'JSON inválido: ' + e.message, raw: raw.substring(0, 500), valid: false } }];
}
